import type { Manifest } from 'vite';
import type { MainAssets } from './types';

import fs from 'node:fs';
import path from 'node:path';

import { ASSETS_CONFIG } from '@nordic/assets-config';

import { readJsonFileSync } from '../../utils/fs';
import { MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX } from '../regex';

function createBaseManifestEntries(clientStats: Manifest | null) {
  const manifest =
    readJsonFileSync<Record<string, string>>(ASSETS_CONFIG.MANIFEST_PATH) ?? {};
  const entries = Object.entries(manifest);

  if (!clientStats) {
    return entries;
  }

  return entries.filter(([key, value]) => {
    const entry = path.join(ASSETS_CONFIG.PREFIX, key);

    return (
      !MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX.test(value) ||
      clientStats[entry] ||
      clientStats[
        entry.replace(MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX, '.js')
      ] ||
      // eslint-disable-next-line security/detect-non-literal-fs-filename
      (__DEV__ && fs.existsSync(path.join(ASSETS_CONFIG.PUBLIC_DIR, value)))
    );
  });
}

export function createManifestEntries() {
  const clientStats = readJsonFileSync<Manifest>(
    ASSETS_CONFIG.CLIENT_STATS_PATH,
  );
  const baseManifestEntries = createBaseManifestEntries(clientStats);
  const mainAssetsManifestEntries: Array<[string, MainAssets]> = [];

  return { baseManifestEntries, mainAssetsManifestEntries };
}
